In the javascript, the operation is as follows:
function(d,e){
    e=(e%d.length+d.length)%d.length;
    d.splice(-e).reverse().forEach(
        function(f){
            d.unshift(f)
        }
    )
}

Effectively, this moves the last e elements of d to the beginning.
